      { id: "cli-3-2", group: "1. Create and Attach Internet Gateway", task: "Attach the IGW to your VPC", expected: "aws ec2 attach-internet-gateway --internet-gateway-id $IGW_ID --vpc-id $VPC_ID", hint: "Attach IGW to VPC.", breakdown: "aws ec2 attach-internet-gateway -> Take the door we just built...\n--internet-gateway-id $IGW_ID -> ...(reading the door's ID)...\n--vpc-id $VPC_ID -> ...and physically attach it to our plot of land." },
      { id: "cli-3-3", group: "1. Create and Attach Internet Gateway", task: "Print confirmation of IGW attachment", expected: "echo \"Internet Gateway attached: $IGW_ID\"", regex: /^echo\s+["'].*["']$/, hint: "Echo success.", breakdown: "echo -> Print a success message confirming the door is attached." },
      { id: "cli-3-4", group: "2. Create Public Route Table and Default Route", task: "Create a Public Route Table and save ID", expected: "PUB_RT=$(aws ec2 create-route-table --vpc-id $VPC_ID --query 'RouteTable.RouteTableId' --output text)", regex: /^([a-zA-Z0-9_-]+)=\$\(aws ec2 create-route-table --vpc-id \$[a-zA-Z0-9_-]+ --query 'RouteTable\.RouteTableId' --output text\)$/, hint: "Create Public Route Table.", breakdown: "PUB_RT=$() -> Create a box for our Public Route Table.\naws ec2 create-route-table -> Hey AWS, build a new blank Hallway Sign." },
      { id: "cli-3-5", group: "2. Create Public Route Table and Default Route", task: "Start creating a route in the table", expected: "aws ec2 create-route \\", hint: "Start create route command.", breakdown: "aws ec2 create-route \\ -> Paint an instruction on the sign." },
      { id: "cli-3-6", group: "2. Create Public Route Table and Default Route", task: "Specify the Public Route Table ID", expected: "--route-table-id $PUB_RT \\", hint: "Target the Public RT.", breakdown: "--route-table-id $PUB_RT \\ -> Paint it on this specific sign." },
      { id: "cli-3-7", group: "2. Create Public Route Table and Default Route", task: "Set destination to all internet traffic (0.0.0.0/0)", expected: "--destination-cidr-block 0.0.0.0/0 \\", hint: "Target all internet traffic.", breakdown: "--destination-cidr-block 0.0.0.0/0 \\ -> If someone wants to go to 0.0.0.0/0 (which is cloud math for 'Anywhere on the public internet')..." },
      { id: "cli-3-8", group: "2. Create Public Route Table and Default Route", task: "Point the route to the Internet Gateway", expected: "--gateway-id $IGW_ID", hint: "Point to the IGW.", breakdown: "--gateway-id $IGW_ID -> ...tell them to walk through the Front Door." },
      { id: "cli-3-9", group: "3. Associate Subnets with Public Route Table", task: "Associate the route table with Public Subnet 1", expected: "aws ec2 associate-route-table --subnet-id $PUB_SUB_1 --route-table-id $PUB_RT", hint: "Associate with Public Subnet 1.", breakdown: "aws ec2 associate-route-table -> Take this finished sign and hang it up inside Lobby 1 ($PUB_SUB_1)." },
      { id: "cli-3-10", group: "3. Associate Subnets with Public Route Table", task: "Associate the route table with Public Subnet 2", expected: "aws ec2 associate-route-table --subnet-id $PUB_SUB_2 --route-table-id $PUB_RT", hint: "Associate with Public Subnet 2.", breakdown: "aws ec2 associate-route-table -> Take this finished sign and hang it up inside Lobby 2 ($PUB_SUB_2)." },
      { id: "cli-3-11", group: "3. Associate Subnets with Public Route Table", task: "Print success message for routing", expected: "echo \"Public routing successfully configured.\"", regex: /^echo\s+["'].*["']$/, hint: "Echo success.", breakdown: "echo -> Print a success message. The Lobbies now know how to reach the outside world!" }
