      { id: "cli-11-2", group: "1. Retrieve Endpoints and Connect via SSM", task: "Specify the DB identifier", expected: "--db-instance-identifier restaurant-db \\", regex: /^--db-instance-identifier\s+[a-zA-Z0-9_-]+\s*\\$/, hint: "Target DB.", breakdown: "--db-instance-identifier restaurant-db \\ -> Look up this specific database." },
      { id: "cli-11-3", group: "1. Retrieve Endpoints and Connect via SSM", task: "Filter output for the endpoint address", expected: "--query 'DBInstances[0].Endpoint.Address' \\", hint: "Query endpoint.", breakdown: "--query 'DBInstances[0].Endpoint.Address' \\ -> Just give me its internal web address." },
      { id: "cli-11-4", group: "1. Retrieve Endpoints and Connect via SSM", task: "Set output to text and close assignment", expected: "--output text)", hint: "Output text.", breakdown: "--output text) -> Save it as plain text." },
      { id: "cli-11-5", group: "1. Retrieve Endpoints and Connect via SSM", task: "Start describing EC2 and save a running ID", expected: "CHEF_ID=$(aws ec2 describe-instances \\", regex: /^([a-zA-Z0-9_-]+)=\$\(aws ec2 describe-instances \\$/, hint: "Start describe EC2.", breakdown: "CHEF_ID=$() -> Create a box for a Chef's ID.\naws ec2 describe-instances \\ -> Hey AWS, look up the details for our Chefs." },
      { id: "cli-11-6", group: "1. Retrieve Endpoints and Connect via SSM", task: "Filter by ASG name and running state", expected: "--filters \"Name=tag:aws:autoscaling:groupName,Values=RestaurantASG\" \"Name=instance-state-name,Values=running\" \\", regex: /^--filters\s+"Name=tag:aws:autoscaling:groupName,Values=[a-zA-Z0-9_-]+"\s+"Name=instance-state-name,Values=running"\s*\\$/, hint: "Filter by ASG.", breakdown: "--filters ... -> Only look for Chefs that were hired by our Kitchen Manager AND are currently running." },
      { id: "cli-11-7", group: "1. Retrieve Endpoints and Connect via SSM", task: "Filter output for the first instance ID", expected: "--query 'Reservations[0].Instances[0].InstanceId' \\", hint: "Query ID.", breakdown: "--query 'Reservations[0].Instances[0].InstanceId' \\ -> Just give me the ID of the very first Chef you find." },
      { id: "cli-11-8", group: "1. Retrieve Endpoints and Connect via SSM", task: "Set output to text and close assignment", expected: "--output text)", hint: "Output text.", breakdown: "--output text) -> Save it as plain text." },
      { id: "cli-11-9", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print a separator line", expected: "echo \"===========================================\"", regex: /^echo\s+["'].*["']$/, hint: "Echo line.", breakdown: "echo -> Print a nice separator line." },
      { id: "cli-11-10", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print the DB endpoint", expected: "echo \"Database Endpoint: $DB_ENDPOINT\"", regex: /^echo\s+["'].*["']$/, hint: "Echo DB.", breakdown: "echo -> Print the Database Endpoint so we can copy it." },
      { id: "cli-11-11", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print the target instance ID", expected: "echo \"Target Instance: $CHEF_ID\"", regex: /^echo\s+["'].*["']$/, hint: "Echo EC2.", breakdown: "echo -> Print the Chef's ID so we know who we are talking to." },
      { id: "cli-11-12", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print a separator line", expected: "echo \"===========================================\"", regex: /^echo\s+["'].*["']$/, hint: "Echo line.", breakdown: "echo -> Print a nice separator line." },
      { id: "cli-11-13", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print instruction for SSM", expected: "echo \"Run this command to connect to the private server:\"", regex: /^echo\s+["'].*["']$/, hint: "Echo message.", breakdown: "echo -> Print instructions." },
      { id: "cli-11-14", group: "1. Retrieve Endpoints and Connect via SSM", task: "Print the SSM start-session command", expected: "echo \"aws ssm start-session --target $CHEF_ID\"", regex: /^echo\s+["'].*["']$/, hint: "Echo SSM command.", breakdown: "echo \"aws ssm start-session...\" -> Print the exact command we need to securely log into the Chef without SSH!" }
